create table dirkspzm32.s_qs_babtec_art (
    artikel        varchar2(30 char) not null enable,
    artbez1        varchar2(50 char),
    artbez2        varchar2(50 char),
    art_zeichnr    varchar2(30 char),
    art_zeichstand varchar2(30 char),
    art_zeichindex varchar2(30 char),
    archiv         number(*, 5),
    benutzer1      varchar2(60 char),
    benutzer2      varchar2(60 char),
    benutzer3      varchar2(60 char),
    benutzer4      varchar2(60 char),
    benutzer5      varchar2(60 char),
    benutzer6      varchar2(60 char),
    art_notiz      varchar2(255 char),
    status         varchar2(3 char) default 'N' not null enable,
    fehler_code    number(*, 5),
    fehler_text    varchar2(255 char),
    erstell_datum  date default sysdate not null enable,
    bearb_datum    date
);

alter table dirkspzm32.s_qs_babtec_art
    add constraint pk_s_qs_babtec_art primary key ( artikel )
        using index enable;


